+    #[test]
+    fn law_debug_clone_copy_eq_hash() {
+        use std::collections::HashSet;
+        let l = Law::SeverityOrder;
+        let l2 = l; // Copy
+        let l3 = l.clone();
+        assert_eq!(l, l2);
+        assert_eq!(l, l3);
+        assert_ne!(l, Law::JoinCommutativity);
+        let dbg = format!("{l:?}");
+        assert!(dbg.contains("SeverityOrder"));
+        let mut set = HashSet::new();
+        set.insert(l);
+        assert!(set.contains(&l2));
+    }
